import android.content.Context
import android.content.SharedPreferences
import android.hardware.biometrics.BiometricManager
import android.hardware.biometrics.BiometricPrompt
import android.os.Build
import android.os.CancellationSignal
import androidx.annotation.RequiresApi
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.widget.Button
import android.widget.Toast
import androidx.core.content.ContextCompat
import android.content.Intent
import android.view.View
import android.widget.EditText
import android.widget.TextView

class LoginActivity : AppCompatActivity() {
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var cancellationSignal: CancellationSignal
    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var passwordEditText: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button
    private lateinit var forgotPasswordTextView: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        initViews()
        sharedPreferences = getSharedPreferences("auth", Context.MODE_PRIVATE)
        
        if (isUserAuthenticated()) {
            navigateToHome()
            return
        }

        setupBiometricPrompt()
        setupClickListeners()
    }

    private fun initViews() {
        passwordEditText = findViewById(R.id.passwordEditText)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)
        forgotPasswordTextView = findViewById(R.id.forgotPasswordTextView)
    }

    private fun setupClickListeners() {
        loginButton.setOnClickListener { attemptLogin() }
        biometricButton.setOnClickListener { startBiometricAuthentication() }
        forgotPasswordTextView.setOnClickListener { 
            Toast.makeText(this, "Password recovery feature", Toast.LENGTH_SHORT).show() 
        }
    }

    private fun setupBiometricPrompt() {
        biometricPrompt = BiometricPrompt.Builder(this)
            .setTitle("Biometric Authentication")
            .setSubtitle("Use fingerprint to access app")
            .setNegativeButtonText("Use Password")
            .build()

        biometricPrompt.authenticate(
            cancellationSignal,
            ContextCompat.getMainExecutor(this),
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    storeAuthenticationStatus(true)
                    navigateToHome()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(this@LoginActivity, "Authentication failed", Toast.LENGTH_SHORT).show()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                        showPasswordLogin()
                    } else {
                        Toast.makeText(this@LoginActivity, "Error: $errString", Toast.LENGTH_SHORT).show()
                    }
                }
            }
        )
    }

    private fun startBiometricAuthentication() {
        if (isBiometricAvailable()) {
            cancellationSignal = CancellationSignal()
            setupBiometricPrompt()
        } else {
            showPasswordLogin()
        }
    }

    private fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(this)
        return biometricManager.canAuthenticate() == BiometricManager.BIOMETRIC_SUCCESS
    }

    private fun attemptLogin() {
        val password = passwordEditText.text.toString()
        if (password.isNotEmpty()) {
            // Simple password validation - in real app, implement proper authentication
            if (password == "123456") {
                storeAuthenticationStatus(true)
                navigateToHome()
            } else {
                Toast.makeText(this, "Invalid password", Toast.LENGTH_SHORT).show()
            }
        } else {
            Toast.makeText(this, "Please enter password", Toast.LENGTH_SHORT).show()
        }
    }

    private fun showPasswordLogin() {
        passwordEditText.visibility = View.VISIBLE
        loginButton.visibility = View.VISIBLE
        biometricButton.visibility = View.GONE
        passwordEditText.requestFocus()
    }

    private fun isUserAuthenticated(): Boolean {
        return sharedPreferences.getBoolean("is_authenticated", false)
    }

    private fun storeAuthenticationStatus(isAuthenticated: Boolean) {
        sharedPreferences.edit().putBoolean("is_authenticated", isAuthenticated).apply()
    }

    private fun navigateToHome() {
        val intent = Intent(this, HomeActivity::class.java)
        startActivity(intent)
        finish()
    }
}

class HomeActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)
        supportActionBar?.title = "Welcome"
    }
}